mapper.select:
SELECT c.user_id AS userId, c.avatar, c.nickname, c.content, c.create_time AS createTime, c.article_id AS articleId, a.cover AS articleCover FROM t_comment c INNER JOIN t_article a ON c.article_id = a.id WHERE c.is_deleted = 0
AND c.user_id = #{userId}
AND a.user_id = #{userId} AND c.user_id != #{userId}
AND ( c.user_id = #{userId} OR (a.user_id = #{userId} AND c.user_id != #{userId}) )
AND a.is_published != 2
ORDER BY c.create_time DESC
